import { ChartContainer, ChartTooltipContent, defaultChartConfig } from "@/components/shared/Chart"
import {
    ComposedChart,
    Line,
    Area,
    Bar,
    XAxis,
    CartesianGrid,
    Tooltip,
    Scatter,
} from 'recharts';


const data = [
    {
        month: 'Jan',
        visitors: 590,
        signups: 800,
        bounceRate: 1400,
        returnUsers: 490,
    },
    {
        month: 'Feb',
        visitors: 868,
        signups: 967,
        bounceRate: 1506,
        returnUsers: 590,
    },
    {
        month: 'Mar',
        visitors: 1397,
        signups: 1098,
        bounceRate: 989,
        returnUsers: 350,
    },
