        visitors: 1520,
        signups: 1108,
        bounceRate: 1100,
        returnUsers: 460,
    },
    {
        month: 'Jun',
        visitors: 1400,
        signups: 680,
        bounceRate: 1700,
        returnUsers: 380,
    }
]

const nameKey: Record<string, string> = {
    signups: 'Signups',
    bounceRate: 'Bounce Rate',
    returnUsers: 'Return Users',
    visitors: 'Visitors'
}

const Compose = () => {
    return (
        <ChartContainer>
            <ComposedChart
            height={300}
            data={data}
            margin={{
                top: 20,
                right: 20,
